#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    int max_count = 0;
    int count[1001] = {0};
    for (int i = 0; i < n; i++) {
        count[a[i]]++;
        if (count[a[i]] > max_count) {
            max_count = count[a[i]];
        }
    }
    printf("%d\n", n - max_count);
    return 0;
}

