        int n = scanner.nextInt();
        int[] a = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = scanner.nextInt();
        }
        int max_count = 0;
        int[] count = new int[1001];
        for (int i = 0; i < n; i++) {
            count[a[i]]++;
            if (count[a[i]] > max_count) {
                max_count = count[a[i]];
            }
        }
        System.out.println(n - max_count);
    }
}

