const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let a;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        a = input.split(' ').map(Number);
        let max_count = 0;
        let count = new Array(1001).fill(0);
        for (let i = 0; i < n; i++) {
            count[a[i]]++;
            if (count[a[i]] > max_count) {
                max_count = count[a[i]];
            }
        }
        console.log(n - max_count);
        rl.close();
    }
});

